import { GoogleGenAI, Type } from "@google/genai";
import { DashboardData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getMarketingInsights = async (data: DashboardData) => {
  const prompt = `
    Analyze this marketing performance data and provide strategic insights:
    Data Summary:
    - Current Metrics: ${JSON.stringify(data.metrics)}
    - Channel Breakdown: ${JSON.stringify(data.channelPerformance)}
    - Competitor Benchmarking: ${JSON.stringify(data.competitors)}

    Please provide:
    1. A summary of overall performance.
    2. Identification of top performing and underperforming channels.
    3. Strategic recommendations to improve ROAS.
    4. Competitor analysis and how we compare.
    5. At least 3 specific action items for next month.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.7,
        topP: 0.95,
        topK: 40,
      }
    });

    return response.text;
  } catch (error) {
    console.error("Error fetching Gemini insights:", error);
    return "I'm sorry, I encountered an error while analyzing your data. Please check your API key or try again later.";
  }
};

import React from 'react';
import { MarketingMetric } from '../types';

interface StatCardProps {
  metric: MarketingMetric;
}

const StatCard: React.FC<StatCardProps> = ({ metric }) => {
  const formatValue = (val: number, format: MarketingMetric['format']) => {
    if (format === 'currency') return `$${val.toLocaleString()}`;
    if (format === 'percentage') return `${val}%`;
    return val.toLocaleString();
  };

  const isPositive = metric.change >= 0;
  const trendColor = metric.trend === 'up' 
    ? (isPositive ? 'text-green-600' : 'text-red-600')
    : (!isPositive ? 'text-green-600' : 'text-red-600');

  return (
    <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm transition-all hover:shadow-md">
      <div className="flex justify-between items-start mb-2">
        <h3 className="text-sm font-medium text-slate-500 uppercase tracking-wider">{metric.label}</h3>
        <span className={`text-xs font-semibold px-2 py-1 rounded-full bg-opacity-10 ${isPositive ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
          {isPositive ? '+' : ''}{metric.change}%
        </span>
      </div>
      <div className="flex items-baseline gap-2">
        <p className="text-2xl font-bold text-slate-900">
          {formatValue(metric.value, metric.format)}
        </p>
      </div>
    </div>
  );
};

export default StatCard;

