/**
 * Uses Google Search grounding to "pull" live market data and competitor news.
 * This acts as our real-time data connector for external market trends.
 */
export const fetchLiveMarketIntel = async (channel: string): Promise<LiveMarketReport> => {
  const prompt = `
    Conduct real-time market research for the marketing channel: ${channel}.
    Find:
    1. Latest industry benchmarks (Average CTR, CPC, and Conversion Rates) for 2024/2025.
    2. Recent significant moves or news from major competitors in this space.
    3. Emerging trends or platform changes that marketing teams should know.

    Be specific with numbers and mention specific competitors where possible.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((chunk: any) => ({
        title: chunk.web?.title || 'Source',
        uri: chunk.web?.uri || ''
      }))
      .filter((s: any) => s.uri) || [];

    return {
      summary: response.text || "No data found.",
      sources: sources
    };
  } catch (error) {
    console.error("Error fetching live intel:", error);
    throw error;
  }
};

