import { GoogleGenAI, Type } from "@google/genai";
import { DashboardData, LiveMarketReport, SeoAuditData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getMarketingInsights = async (data: DashboardData) => {
  const prompt = `Analyze marketing performance: ${JSON.stringify(data)}. Provide summary, channel performance, and 3 action items.`;
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text;
  } catch (error) {
    return "Error generating insights.";
  }
};

export const fetchLiveMarketIntel = async (channel: string): Promise<LiveMarketReport> => {
  const prompt = `Real-time research for ${channel}: benchmarks, competitor moves, and trends.`;
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: { tools: [{ googleSearch: {} }] },
    });
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((chunk: any) => ({ title: chunk.web?.title || 'Source', uri: chunk.web?.uri || '' }))
      .filter((s: any) => s.uri) || [];
    return { summary: response.text || "No data.", sources };
  } catch (error) { throw error; }
};

export const runSeoAudit = async (domain: string): Promise<{ analysis: string; sources: any[] }> => {
  const prompt = `Perform a comprehensive SEO audit for ${domain}. Include domain authority estimate, top 5 keywords they rank for, backlink profile summary, and competitive gap analysis.`;
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: { tools: [{ googleSearch: {} }] },
    });
    return { 
      analysis: response.text, 
      sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || [] 
    };
  } catch (error) { throw error; }
};

export const suggestSocialContent = async (topic: string, channel: string) => {
  const prompt = `Generate 3 high-engagement post ideas for ${channel} about ${topic}. Include catchy captions and trending hashtags.`;
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text;
  } catch (error) { return "Error generating suggestions."; }
};

